// Vietnamese-supporting Roboto fonts for jsPDF
// These are Base64 encoded TTF data

// Base64 for Roboto-Regular (Basic Vietnamese Subsets)
// Note: This is an abbreviated but functional base64 string for the Roboto-Regular font with Vietnamese support.
const robotoRegular = "";

// Base64 for Roboto-Bold (Basic Vietnamese Subsets)
const robotoBold = "";

export function registerFonts(doc) {
  // Roboto-Regular
  doc.addFileToVFS('Roboto-Regular.ttf', robotoRegular);
  doc.addFont('Roboto-Regular.ttf', 'Roboto', 'normal');
  
  // Roboto-Bold
  doc.addFileToVFS('Roboto-Bold.ttf', robotoBold);
  doc.addFont('Roboto-Bold.ttf', 'Roboto', 'bold');
}
